// rch/src/main.rs
use clap_complete::CompleteEnv;

fn main() {
    // Handle dynamic completions first (exits if handling completion request)
    CompleteEnv::with_factory(Cli::command).complete();

    // Normal execution continues
    let cli = Cli::parse();
    run(cli).unwrap_or_else(|e| {
        eprintln!("{:?}", e);
        std::process::exit(1);
    });
}
