// rch/src/cli.rs
use crate::completions::*;
use clap::{Parser, Subcommand, ValueHint};
use clap_complete::ArgValueCompleter;

#[derive(Parser)]
#[command(name = "rch", about = "Remote Compilation Helper")]
pub struct Cli {
    /// Config file path
    #[arg(long, short, global = true, value_hint = ValueHint::FilePath)]
    pub config: Option<PathBuf>,

    /// Log level
    #[arg(long, global = true, add = ArgValueCompleter::new(complete_log_levels))]
    pub log_level: Option<String>,

    #[command(subcommand)]
    pub command: Commands,
}

#[derive(Subcommand)]
pub enum Commands {
    /// Worker management
    Workers {
        #[command(subcommand)]
        action: WorkerAction,
    },

    /// Build commands
    Build {
        /// Target worker
        #[arg(long, add = ArgValueCompleter::new(complete_worker_ids))]
        worker: Option<String>,

        /// Rust toolchain
        #[arg(long, add = ArgValueCompleter::new(complete_toolchains))]
        toolchain: Option<String>,

        /// Additional cargo arguments
        #[arg(trailing_var_arg = true)]
        args: Vec<String>,
    },

    /// Generate shell completions
    Completions {
        #[arg(value_enum)]
        shell: clap_complete::Shell,
    },
}

#[derive(Subcommand)]
pub enum WorkerAction {
    /// List configured workers
    List,

    /// Probe worker connectivity
    Probe {
        /// Worker ID to probe (or --all)
        #[arg(add = ArgValueCompleter::new(complete_worker_ids))]
        worker: Option<String>,

        /// Probe all workers
        #[arg(long)]
        all: bool,
    },

    /// Run benchmarks
    Benchmark {
        /// Worker ID to benchmark
        #[arg(add = ArgValueCompleter::new(complete_worker_ids))]
        worker: Option<String>,
    },
}
